#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, A, B;
        scanf("%d %d %d", &N, &A, &B);
        int faces[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &faces[i]);
        }
        int countA = 0, countB = 0;
        for (int i = 0; i < N; i++) {
            if (faces[i] == A) countA++;
            if (faces[i] == B) countB++;
        }
        double probability = (double)countA / N * (double)countB / N;
        printf("%.10f\n", probability);
    }
    return 0;
}

