import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int A = sc.nextInt();
            int B = sc.nextInt();
            int[] faces = new int[N];
            for (int i = 0; i < N; i++) {
                faces[i] = sc.nextInt();
            }
            int countA = 0, countB = 0;
            for (int i = 0; i < N; i++) {
                if (faces[i] == A) countA++;
                if (faces[i] == B) countB++;
            }
            double probability = (double)countA / N * (double)countB / N;
            System.out.printf("%.10f\n", probability);
        }
    }
}

