const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, A, B] = readline().split(' ').map(Number);
    const faces = readline().split(' ').map(Number);
    const countA = faces.filter(x => x === A).length;
    const countB = faces.filter(x => x === B).length;
    const probability = (countA / N) * (countB / N);
    console.log(probability.toFixed(10));
}
